        }
    }
}

import SwiftData

@Model
class SavedHero {
    var name: String
    var powerLevel: Int
    var dateAdded: Date

    init(name: String, powerLevel: Int) {
        self.name = name
        self.powerLevel = powerLevel
        self.dateAdded = Date()
    }
}

