    var heroes: [HeroResponse] = []
    var isLoading = false

    func loadHeroes() async {
        isLoading = true
        do {
            let url = URL(string: "https://api.example.com/heroes")!
            let (data, _) = try await URLSession.shared.data(from: url)
            heroes = try JSONDecoder().decode([HeroResponse].self, from: data)
        } catch {
            print("Error: \(error)")
        }
        isLoading = false
    }
}

struct BouncingHero: View {
    @State private var isJumping = false

    var body: some View {
        Text("🦸")
            .font(.system(size: 60))
            .offset(y: isJumping ? -50 : 0)
            .animation(
                .spring(response: 0.3, dampingFraction: 0.5),
                value: isJumping
            )
            .onTapGesture {
                isJumping.toggle()
            }
    }
}

struct DraggableHero: View {
    @State private var position = CGSize.zero

    var body: some View {
        Text("🦸")
            .font(.system(size: 60))
            .offset(position)
            .gesture(
                DragGesture()
                    .onChanged { value in
                        position = value.translation
                    }
                    .onEnded { _ in
                        withAnimation(.spring()) {
                            position = .zero
                        }
                    }
            )
    }
}

