import XCTest
@testable import CaptainSwift

final class UserProgressTests: XCTestCase {

    func testNoCompletionsOnInit() {
        let progress = UserProgress()
        XCTAssertTrue(progress.completedChapterIDs.isEmpty)
    }

    func testMarkingChapterCompleted() {
        var progress = UserProgress()
        progress.completedChapterIDs.insert(1)
        XCTAssertTrue(progress.isCompleted(1))
        XCTAssertFalse(progress.isCompleted(2))
    }
}

func loadChapters() {
    print("📖 Loading chapters...")
    guard let url = Bundle.main.url(
        forResource: "chapter",
        withExtension: "json"
    ) else {
        print("❌ chapter.json not found")
        return
    }
    print("✅ Found at \(url)")
}
